import java.util.Scanner;

public class SecureBufferUsage {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        char[] buffer = new char[10];

        if (input.length() > buffer.length) {
            System.out.println("Input string is too long. Please enter a string with length <= 10.");
            return;
        }

        input.getChars(0, input.length(), buffer, 0); // Safe point

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
